/**
 * Represents one piece of diagnostics for the current DQL in the DQL editor.
 * @public
 */
export interface DQLEditorValidityInfo {
    /** Represents how serious the problem is. */
    severity: 'error' | 'warning' | 'info';
    /** Describes the problem. */
    message: string;
    /** Start position in the editor. */
    from: number;
    /** End position in the editor. */
    to: number;
}
